    function unpackedState()
        external
        view
        returns (uint64 periodVolumeUsd6, uint96 emaVolumeUsd6Scaled, uint64 periodStart, uint8 feeIdx)
    {
        (periodVolumeUsd6, emaVolumeUsd6Scaled, periodStart, feeIdx,,,,,) = _unpackState(_state);
    }

